import { useState, useEffect, useRef } from "react";
import { MapPin, Search, Navigation, X, Plus, Minus } from "lucide-react";
import { Button } from "@/components/ui/button";
import { Input } from "@/components/ui/input";
import { Sheet, SheetContent, SheetHeader, SheetTitle, SheetTrigger } from "@/components/ui/sheet";
import { Select, SelectContent, SelectItem, SelectTrigger, SelectValue } from "@/components/ui/select";
import { useToast } from "@/hooks/use-toast";
import { useQuery } from "@tanstack/react-query";

// Mapbox types
interface MapboxFeature {
  id: string;
  place_name: string;
  center: [number, number];
  geometry: {
    coordinates: [number, number];
  };
}

interface MapboxResponse {
  features: MapboxFeature[];
}

interface LocationData {
  address: string;
  latitude?: number;
  longitude?: number;
}

interface LocationPickerProps {
  value: LocationData;
  onChange: (location: LocationData) => void;
  placeholder?: string;
  className?: string;
}

const MAPBOX_TOKEN = import.meta.env.VITE_MAPBOX_TOKEN;

// Debounced search hook
function useDebounce<T>(value: T, delay: number): T {
  const [debouncedValue, setDebouncedValue] = useState<T>(value);

  useEffect(() => {
    const handler = setTimeout(() => {
      setDebouncedValue(value);
    }, delay);

    return () => {
      clearTimeout(handler);
    };
  }, [value, delay]);

  return debouncedValue;
}

export function LocationPicker({ value, onChange, placeholder = "Enter location", className }: LocationPickerProps) {
  const [searchQuery, setSearchQuery] = useState(value.address || "");
  const [isMapOpen, setIsMapOpen] = useState(false);
  const [mapInstance, setMapInstance] = useState<any>(null);
  const [marker, setMarker] = useState<any>(null);
  const [mapStyle, setMapStyle] = useState("streets-v12");
  const mapContainer = useRef<HTMLDivElement>(null);
  const resizeObserver = useRef<ResizeObserver | null>(null);
  const { toast } = useToast();

  const debouncedQuery = useDebounce(searchQuery, 300);

  // Mapbox Places API query
  const { data: suggestions, isLoading } = useQuery<MapboxFeature[]>({
    queryKey: ['places', debouncedQuery],
    queryFn: async () => {
      if (!debouncedQuery || debouncedQuery.length < 3) return [];

      const response = await fetch(
        `https://api.mapbox.com/geocoding/v5/mapbox.places/${encodeURIComponent(debouncedQuery)}.json?access_token=${MAPBOX_TOKEN}&limit=5&country=NG`
      );

      if (!response.ok) throw new Error('Failed to fetch suggestions');

      const data: MapboxResponse = await response.json();
      return data.features;
    },
    enabled: debouncedQuery.length >= 3,
    staleTime: 5 * 60 * 1000, // 5 minutes
  });

  // Reverse geocoding query
  const reverseGeocode = async (lat: number, lng: number): Promise<string> => {
    try {
      const response = await fetch(
        `https://api.mapbox.com/geocoding/v5/mapbox.places/${lng},${lat}.json?access_token=${MAPBOX_TOKEN}&limit=1`
      );

      if (!response.ok) throw new Error('Failed to reverse geocode');

      const data: MapboxResponse = await response.json();
      return data.features[0]?.place_name || 'Unknown location';
    } catch (error) {
      console.error('Reverse geocoding error:', error);
      return 'Unknown location';
    }
  };

  // Get current location
  const getCurrentLocation = () => {
    if (!navigator.geolocation) {
      toast({
        title: "Location not supported",
        description: "Your browser doesn't support location services",
        variant: "destructive",
      });
      return;
    }

    navigator.geolocation.getCurrentPosition(
      async (position) => {
        const { latitude, longitude } = position.coords;
        const address = await reverseGeocode(latitude, longitude);

        const locationData: LocationData = {
          address,
          latitude,
          longitude,
        };

        setSearchQuery(address);
        onChange(locationData);

        toast({
          title: "Location found",
          description: "Your current location has been set",
        });
      },
      (error) => {
        console.error('Geolocation error:', error);
        toast({
          title: "Location access denied",
          description: "Please allow location access or enter your address manually",
          variant: "destructive",
        });
      },
      {
        enableHighAccuracy: true,
        timeout: 10000,
        maximumAge: 300000, // 5 minutes
      }
    );
  };

  // Select suggestion
  const selectSuggestion = (feature: MapboxFeature) => {
    const locationData: LocationData = {
      address: feature.place_name,
      latitude: feature.center[1],
      longitude: feature.center[0],
    };

    setSearchQuery(feature.place_name);
    onChange(locationData);
  };

  // Map control functions
  const zoomIn = () => {
    if (mapInstance) {
      mapInstance.zoomIn();
    }
  };

  const zoomOut = () => {
    if (mapInstance) {
      mapInstance.zoomOut();
    }
  };

  const changeMapStyle = (style: string) => {
    setMapStyle(style);
    if (mapInstance) {
      mapInstance.setStyle(`mapbox://styles/mapbox/${style}`);
    }
  };

  // Robust map initialization with ResizeObserver
  useEffect(() => {
    if (isMapOpen && MAPBOX_TOKEN && !mapInstance) {
      let currentAttempt = 0;
      let timeoutIds: NodeJS.Timeout[] = [];

      const initializeMapWithRetry = () => {
        const maxAttempts = 8;
        const baseDelay = 100;

        const attemptInitialization = () => {
          if (currentAttempt >= maxAttempts) {
            toast({
              title: "Map loading failed",
              description: "Please use the search feature to find your location.",
              variant: "destructive",
            });
            return;
          }

          if (!mapContainer.current) {
            currentAttempt++;
            const delay = baseDelay * Math.pow(1.5, currentAttempt);
            const timeoutId = setTimeout(attemptInitialization, delay);
            timeoutIds.push(timeoutId);
            return;
          }

          // Use requestAnimationFrame to ensure DOM is fully rendered
          requestAnimationFrame(() => {
            const containerRect = mapContainer.current?.getBoundingClientRect();

            if (!containerRect || containerRect.width === 0 || containerRect.height === 0) {
              currentAttempt++;
              const delay = baseDelay * Math.pow(1.5, currentAttempt);
              const timeoutId = setTimeout(attemptInitialization, delay);
              timeoutIds.push(timeoutId);
              return;
            }

            // Container is ready, initialize map
            import('mapbox-gl')
              .then((mapboxModule) => {
                const mapboxgl = mapboxModule.default;
                (mapboxgl as any).accessToken = MAPBOX_TOKEN;

                const map = new mapboxgl.Map({
                  container: mapContainer.current!,
                  style: `mapbox://styles/mapbox/${mapStyle}`,
                  center: value.longitude && value.latitude ? [value.longitude, value.latitude] : [3.3792, 6.5244],
                  zoom: value.longitude && value.latitude ? 15 : 10,
                });

                map.on('load', () => {
                  // Ensure map is properly sized after sheet animation
                  setTimeout(() => map.resize(), 100);
                });

                map.on('error', (e) => {
                  toast({
                    title: "Map error",
                    description: "There was an error loading the map. Please try again.",
                    variant: "destructive",
                  });
                });

                // Add marker
                const newMarker = new mapboxgl.Marker({ draggable: true })
                  .setLngLat(value.longitude && value.latitude ? [value.longitude, value.latitude] : [3.3792, 6.5244])
                  .addTo(map);

                // Handle marker drag
                newMarker.on('dragend', async () => {
                  const lngLat = newMarker.getLngLat();
                  const address = await reverseGeocode(lngLat.lat, lngLat.lng);

                  const locationData: LocationData = {
                    address,
                    latitude: lngLat.lat,
                    longitude: lngLat.lng,
                  };

                  setSearchQuery(address);
                  onChange(locationData);
                });

                // Setup ResizeObserver for container dimension changes
                if (mapContainer.current && typeof ResizeObserver !== 'undefined') {
                  resizeObserver.current = new ResizeObserver(() => {
                    if (map) {
                      map.resize();
                    }
                  });
                  resizeObserver.current.observe(mapContainer.current);
                }

                setMapInstance(map);
                setMarker(newMarker);
              })
              .catch((error) => {
                toast({
                  title: "Map loading failed",
                  description: "Please use the search feature to find your location.",
                  variant: "destructive",
                });
              });
          });
        };

        attemptInitialization();
      };

      initializeMapWithRetry();

      return () => {
        timeoutIds.forEach(clearTimeout);
      };
    }
  }, [isMapOpen, value.latitude, value.longitude, onChange, toast, mapInstance, mapStyle]);

  // Clean up map when sheet closes to allow re-initialization
  useEffect(() => {
    if (!isMapOpen && mapInstance) {
      // Clean up when sheet closes
      if (resizeObserver.current) {
        try {
          resizeObserver.current.disconnect();
        } catch (e) {
          // Ignore cleanup errors
        }
        resizeObserver.current = null;
      }
      if (marker) {
        try {
          marker.remove();
        } catch (e) {
          // Ignore cleanup errors
        }
        setMarker(null);
      }
      if (mapInstance) {
        try {
          mapInstance.remove();
        } catch (e) {
          // Ignore cleanup errors
        }
        setMapInstance(null);
      }
    }
  }, [isMapOpen, mapInstance, marker]);

  // Update map center when coordinates change
  useEffect(() => {
    if (mapInstance && marker && value.latitude && value.longitude) {
      const newCenter = [value.longitude, value.latitude];
      mapInstance.setCenter(newCenter);
      marker.setLngLat(newCenter);
    }
  }, [mapInstance, marker, value.latitude, value.longitude]);

  // Cleanup map on unmount
  useEffect(() => {
    return () => {
      if (resizeObserver.current) {
        try {
          resizeObserver.current.disconnect();
        } catch (e) {
          // Ignore cleanup errors
        }
        resizeObserver.current = null;
      }
      if (marker) {
        try {
          marker.remove();
        } catch (e) {
          // Ignore cleanup errors
        }
        setMarker(null);
      }
      if (mapInstance) {
        try {
          mapInstance.remove();
        } catch (e) {
          // Ignore cleanup errors
        }
        setMapInstance(null);
      }
    };
  }, [mapInstance, marker]);

  return (
    <div className={className}>
      <div className="relative">
        <div className="relative">
          <Search className="absolute left-3 top-1/2 transform -translate-y-1/2 text-muted-foreground w-4 h-4" />
          <Input
            type="text"
            placeholder={placeholder}
            value={searchQuery}
            onChange={(e) => setSearchQuery(e.target.value)}
            className="pl-10 pr-4"
            data-testid="input-location-search"
          />
        </div>

        {/* Suggestions dropdown */}
        {suggestions && suggestions.length > 0 && (
          <div className="absolute z-50 w-full mt-1 bg-background border border-border rounded-md shadow-lg max-h-60 overflow-auto">
            {suggestions.map((feature) => (
              <button
                key={feature.id}
                onClick={() => selectSuggestion(feature)}
                className="w-full px-4 py-2 text-left hover:bg-muted transition-colors flex items-center gap-2"
                data-testid={`suggestion-${feature.id}`}
              >
                <MapPin className="w-4 h-4 text-muted-foreground flex-shrink-0" />
                <span className="text-sm">{feature.place_name}</span>
              </button>
            ))}
          </div>
        )}
      </div>

      {/* Action buttons */}
      <div className="flex gap-2 mt-3">
        <Button
          type="button"
          variant="outline"
          size="sm"
          onClick={getCurrentLocation}
          className="flex items-center gap-2"
          data-testid="button-current-location"
        >
          <Navigation className="w-4 h-4" />
          Use my location
        </Button>

        {MAPBOX_TOKEN && (
          <Sheet open={isMapOpen} onOpenChange={setIsMapOpen}>
            <SheetTrigger asChild>
              <Button
                type="button"
                variant="outline"
                size="sm"
                className="flex items-center gap-2"
                data-testid="button-open-map"
              >
                <MapPin className="w-4 h-4" />
                Choose on map
              </Button>
            </SheetTrigger>
            <SheetContent side="bottom" className="h-[80vh] p-0">
              <SheetHeader className="p-4 pb-2">
                <SheetTitle>Choose Location on Map</SheetTitle>
                <p className="text-sm text-muted-foreground">
                  Drag the marker to select your exact location
                </p>
              </SheetHeader>
              <div className="flex-1 relative">
                <div
                  ref={mapContainer}
                  className="w-full h-[calc(80vh-100px)]"
                  data-testid="map-container"
                />

                {/* Map Controls */}
                <div className="absolute top-4 left-4 z-10 flex flex-col gap-2">
                  {/* Zoom Controls */}
                  <div className="bg-background border border-border rounded-md shadow-sm">
                    <Button
                      onClick={zoomIn}
                      size="sm"
                      variant="ghost"
                      className="p-2 h-8 w-8 rounded-none rounded-t-md"
                      data-testid="button-zoom-in"
                    >
                      <Plus className="w-4 h-4" />
                    </Button>
                    <div className="h-px bg-border" />
                    <Button
                      onClick={zoomOut}
                      size="sm"
                      variant="ghost"
                      className="p-2 h-8 w-8 rounded-none rounded-b-md"
                      data-testid="button-zoom-out"
                    >
                      <Minus className="w-4 h-4" />
                    </Button>
                  </div>

                  {/* Map Style Selector */}
                  <div className="bg-background border border-border rounded-md shadow-sm p-2">
                    <Select value={mapStyle} onValueChange={changeMapStyle}>
                      <SelectTrigger className="w-32 h-8" data-testid="select-map-style">
                        <SelectValue />
                      </SelectTrigger>
                      <SelectContent>
                        <SelectItem value="streets-v12">Streets</SelectItem>
                        <SelectItem value="satellite-v9">Satellite</SelectItem>
                        <SelectItem value="outdoors-v12">Outdoors</SelectItem>
                        <SelectItem value="light-v11">Light</SelectItem>
                        <SelectItem value="dark-v11">Dark</SelectItem>
                      </SelectContent>
                    </Select>
                  </div>
                </div>

                {/* Done Button */}
                <Button
                  onClick={() => setIsMapOpen(false)}
                  className="absolute top-4 right-4 z-10"
                  size="sm"
                  data-testid="button-close-map"
                >
                  <X className="w-4 h-4 mr-2" />
                  Done
                </Button>

                {/* Current Location Indicator */}
                {value.latitude && value.longitude && (
                  <div className="absolute bottom-4 left-4 z-10 bg-background/90 border border-border rounded-md px-3 py-2 text-xs">
                    <div className="flex items-center gap-1 text-muted-foreground">
                      <MapPin className="w-3 h-3" />
                      {value.latitude.toFixed(4)}, {value.longitude.toFixed(4)}
                    </div>
                  </div>
                )}
              </div>
            </SheetContent>
          </Sheet>
        )}
      </div>

      {/* Loading indicator */}
      {isLoading && (
        <div className="text-xs text-muted-foreground mt-1">
          Searching locations...
        </div>
      )}

      {/* Selected location info */}
      {value.latitude && value.longitude && (
        <div className="text-xs text-muted-foreground mt-2 flex items-center gap-1">
          <MapPin className="w-3 h-3" />
          Coordinates: {value.latitude.toFixed(4)}, {value.longitude.toFixed(4)}
        </div>
      )}
    </div>
  );
}

client/src/hooks/use-auth.tsx.content:
import { createContext, ReactNode, useContext } from "react";
import {
  useQuery,
  useMutation,
  UseMutationResult,
} from "@tanstack/react-query";
import { insertUserSchema, User as SelectUser, InsertUser } from "@shared/schema";
import { getQueryFn, apiRequest, queryClient } from "../lib/queryClient";
import { useToast } from "@/hooks/use-toast";

type AuthContextType = {
  user: SelectUser | null;
  isLoading: boolean;
  error: Error | null;
  loginMutation: UseMutationResult<SelectUser, Error, LoginData>;
  logoutMutation: UseMutationResult<void, Error, void>;
  registerMutation: UseMutationResult<SelectUser, Error, InsertUser>;
};

type LoginData = {
  username?: string;
  password?: string;
  accessCode?: string;
};

export const AuthContext = createContext<AuthContextType | null>(null);

export function AuthProvider({ children }: { children: ReactNode }) {
  const { toast } = useToast();

  // ⛔️ Do NOT query /api/user on admin routes (prevents 401 noise there)
  const isAdminRoute =
    typeof window !== "undefined" &&
    (window.location.pathname.startsWith("/admin") ||
      window.location.pathname.startsWith("/admin-dashboard"));

  // In resident areas, we ask the API who the user is.
  // On admin routes, we disable this query entirely.
  const {
    data: user,
    error,
    isLoading,
  } = useQuery<SelectUser | null, Error>({
    queryKey: ["/api/user"],
    queryFn: getQueryFn<SelectUser | null>({ on401: "returnNull" }),
    enabled: !isAdminRoute, // <- critical line
  });

  const loginMutation = useMutation({
    mutationFn: async (credentials: LoginData) => {
      // Transform accessCode to username for backend compatibility
      const loginData = credentials.accessCode
        ? { username: credentials.accessCode, password: "access_code_login" }
        : { username: credentials.username, password: credentials.password };

      const res = await apiRequest("POST", "/api/login", loginData);
      return (await res.json()) as SelectUser;
    },
    onSuccess: (user: SelectUser) => {
      queryClient.setQueryData(["/api/user"], user);
    },
    onError: (error: Error) => {
      toast({
        title: "Login failed",
        description: error.message,
        variant: "destructive",
      });
    },
  });

  const registerMutation = useMutation({
    mutationFn: async (credentials: InsertUser) => {
      // Optional: validate on client (keeps your original import in use)
      insertUserSchema.parse(credentials);
      const res = await apiRequest("POST", "/api/register", credentials);
      return (await res.json()) as SelectUser;
    },
    onSuccess: (user: SelectUser) => {
      queryClient.setQueryData(["/api/user"], user);
    },
    onError: (error: Error) => {
      toast({
        title: "Registration failed",
        description: error.message,
        variant: "destructive",
      });
    },
  });

  const logoutMutation = useMutation({
    mutationFn: async () => {
      await apiRequest("POST", "/api/logout");
    },
    onSuccess: () => {
      queryClient.setQueryData(["/api/user"], null);
    },
    onError: (error: Error) => {
      toast({
        title: "Logout failed",
        description: error.message,
        variant: "destructive",
      });
    },
  });

  return (
    <AuthContext.Provider
      value={{
        user: user ?? null,
        isLoading,
        error,
        loginMutation,
        logoutMutation,
        registerMutation,
      }}
    >
      {children}
    </AuthContext.Provider>
  );
}

export function useAuth() {
  const context = useContext(AuthContext);
  if (!context) {
    throw new Error("useAuth must be used within an AuthProvider");
  }
  return context;
}

