              transition={{ duration: 0.6, delay: 1.2 }}
              viewport={{ once: true }}
            >
              <p>© 2025 CityConnect. Building stronger communities through technology.</p>
            </motion.div>

            {/* Floating Elements */}
            <motion.div
              className="absolute top-10 left-10 w-2 h-2 bg-blue-400 rounded-full opacity-40"
