            />
            <motion.div
              className="absolute top-20 right-16 w-1 h-1 bg-purple-400 rounded-full opacity-50"
              animate={{
                y: [0, 15, 0],
                x: [0, -8, 0],
                opacity: [0.5, 1, 0.5],
              }}
              transition={{
                duration: 5,
                repeat: Infinity,
