              }}
            />
            <motion.div
              className="absolute bottom-10 left-16 w-1.5 h-1.5 bg-indigo-400 rounded-full opacity-30"
              animate={{
                y: [0, -10, 0],
                x: [0, 12, 0],
                opacity: [0.3, 0.7, 0.3],
