} from "lucide-react";

export default function ProviderDashboard() {
  const { user, logoutMutation } = useAuth();
  const { toast } = useToast();
  const [isCreateStoreDialogOpen, setIsCreateStoreDialogOpen] = useState(false);
  const [storeFormData, setStoreFormData] = useState({
    name: "",
    description: "",
    location: "",
    phone: "",
    email: ""
  });

  const { data: availableRequests = [] } = useQuery({
    queryKey: ["/api/service-requests", { status: "available" }],
  });

  const { data: myRequests = [] } = useQuery({
    queryKey: ["/api/service-requests"],
  });

  const { data: myStores = [], isLoading: isLoadingStores } = useQuery({
    queryKey: ["/api/provider/stores"],
    queryFn: () => apiRequest("GET", "/api/provider/stores")
  });

  const acceptJobMutation = useMutation({
    mutationFn: async (requestId: string) => {
      return await apiRequest("POST", `/api/service-requests/${requestId}/accept`);
    },
    onSuccess: () => {
      queryClient.invalidateQueries({ queryKey: ["/api/service-requests"] });
      toast({
        title: "Job Accepted",
        description: "You have successfully accepted this job!",
      });
    },
    onError: (error: Error) => {
      toast({
        title: "Error",
        description: error.message,
        variant: "destructive",
      });
    },
  });

  const updateJobStatusMutation = useMutation({
    mutationFn: async ({ requestId, status }: { requestId: string; status: string }) => {
      return await apiRequest("PATCH", `/api/service-requests/${requestId}`, { status });
    },
    onSuccess: () => {
      queryClient.invalidateQueries({ queryKey: ["/api/service-requests"] });
      toast({
        title: "Status Updated",
        description: "Job status has been updated successfully!",
      });
    },
    onError: (error: Error) => {
      toast({
        title: "Error",
        description: error.message,
        variant: "destructive",
      });
    },
  });

  const createStoreMutation = useMutation({
    mutationFn: async (storeData: typeof storeFormData) => {
      return await apiRequest("POST", "/api/provider/stores", storeData);
    },
    onSuccess: () => {
      queryClient.invalidateQueries({ queryKey: ["/api/provider/stores"] });
      setIsCreateStoreDialogOpen(false);
      setStoreFormData({ name: "", description: "", location: "", phone: "", email: "", estateId: "" });
      toast({
        title: "Store Created",
        description: "Your store has been created successfully!",
      });
    },
    onError: (error: any) => {
      toast({
        title: "Error",
        description: error.message || "Failed to create store",
        variant: "destructive",
      });
    },
  });

  const handleLogout = async () => {
    await logoutMutation.mutateAsync();
  };

  const activeJobs = myRequests.filter((r: any) => ['assigned', 'in_progress'].includes(r.status));
  const completedJobs = myRequests.filter((r: any) => r.status === 'completed');

  const stats = {
    available: availableRequests.length,
    active: activeJobs.length,
    completed: completedJobs.length,
    monthlyEarnings: completedJobs.reduce((sum: number, job: any) => {
      const amount = parseFloat(job.budget.split('-')[1]?.replace(/[₦,]/g, '') || '0');
      return sum + (amount || 0);
    }, 0)
  };

  const getStatusColor = (status: string) => {
    switch (status) {
      case 'pending': return 'bg-gray-100 text-gray-800';
      case 'assigned': return 'bg-blue-100 text-blue-800';
      case 'in_progress': return 'bg-yellow-100 text-yellow-800';
      case 'completed': return 'bg-green-100 text-green-800';
      default: return 'bg-gray-100 text-gray-800';
    }
  };

  const getUrgencyColor = (urgency: string) => {
    switch (urgency) {
      case 'emergency': return 'bg-red-100 text-red-800';
      case 'high': return 'bg-orange-100 text-orange-800';
      case 'medium': return 'bg-blue-100 text-blue-800';
      case 'low': return 'bg-green-100 text-green-800';
      default: return 'bg-gray-100 text-gray-800';
    }
  };

  return (
    <div className="min-h-screen bg-background">
      {/* Navigation */}
      <nav className="bg-card shadow-sm border-b border-border">
        <div className="max-w-7xl mx-auto px-4 sm:px-6 lg:px-8">
          <div className="flex justify-between items-center h-16">
            <div className="flex items-center">
              <h1 className="text-xl font-bold text-primary">CityConnect</h1>
              <span className="ml-3 text-sm text-muted-foreground">Provider Dashboard</span>
            </div>
            <div className="flex items-center space-x-4">
              <div className="flex items-center space-x-2">
                <span className="text-sm text-muted-foreground">Rating:</span>
                <div className="flex items-center">
                  <Star className="w-4 h-4 text-yellow-400 fill-current" />
                  <span className="ml-1 font-semibold text-foreground" data-testid="text-provider-rating">
                    {user?.rating || "4.8"}
                  </span>
                </div>
              </div>
              <Button variant="ghost" size="sm" onClick={handleLogout} data-testid="button-logout">
                <LogOut className="w-4 h-4" />
              </Button>
            </div>
          </div>
        </div>
      </nav>

      <div className="max-w-7xl mx-auto px-4 sm:px-6 lg:px-8 py-8">
        {/* Header */}
        <div className="mb-8">
          <h2 className="text-2xl font-bold text-foreground mb-2">
            Welcome, <span data-testid="text-provider-name">{user?.name}!</span>
          </h2>
          <p className="text-muted-foreground">
            {user?.serviceCategory?.replace('_', ' ').replace(/\b\w/g, (l: string) => l.toUpperCase())} • 
            {user?.isApproved ? ' Approved Provider' : ' Pending Approval'}
          </p>
        </div>

        {/* Stats Cards */}
        <div className="grid md:grid-cols-4 gap-6 mb-8">
          <Card>
            <CardContent className="p-6">
              <div className="flex items-center justify-between">
                <div>
                  <p className="text-sm font-medium text-muted-foreground">Available Jobs</p>
                  <p className="text-2xl font-bold text-foreground" data-testid="text-available-jobs">
                    {stats.available}
                  </p>
                </div>
                <div className="bg-accent/10 p-3 rounded-lg">
                  <Briefcase className="w-6 h-6 text-accent" />
                </div>
              </div>
            </CardContent>
          </Card>

          <Card>
            <CardContent className="p-6">
              <div className="flex items-center justify-between">
                <div>
                  <p className="text-sm font-medium text-muted-foreground">Active Jobs</p>
                  <p className="text-2xl font-bold text-foreground" data-testid="text-active-jobs">
                    {stats.active}
                  </p>
                </div>
                <div className="bg-primary/10 p-3 rounded-lg">
                  <Clock className="w-6 h-6 text-primary" />
                </div>
              </div>
            </CardContent>
          </Card>

          <Card>
            <CardContent className="p-6">
              <div className="flex items-center justify-between">
                <div>
                  <p className="text-sm font-medium text-muted-foreground">Completed</p>
                  <p className="text-2xl font-bold text-foreground" data-testid="text-completed-jobs">
                    {stats.completed}
                  </p>
                </div>
                <div className="bg-secondary/10 p-3 rounded-lg">
                  <CheckCircle className="w-6 h-6 text-secondary" />
                </div>
              </div>
            </CardContent>
          </Card>

          <Card>
            <CardContent className="p-6">
              <div className="flex items-center justify-between">
                <div>
                  <p className="text-sm font-medium text-muted-foreground">Earnings</p>
                  <p className="text-2xl font-bold text-foreground" data-testid="text-monthly-earnings">
                    ₦{stats.monthlyEarnings.toLocaleString()}
                  </p>
                </div>
                <div className="bg-green-100 p-3 rounded-lg">
                  <DollarSign className="w-6 h-6 text-green-600" />
                </div>
              </div>
            </CardContent>
          </Card>
        </div>

        {/* Jobs Tabs */}
        <Card>
          <Tabs defaultValue="available">
            <CardHeader>
              <TabsList>
                <TabsTrigger value="available" data-testid="tab-available-jobs">
                  Available Jobs ({stats.available})
                </TabsTrigger>
                <TabsTrigger value="active" data-testid="tab-active-jobs">
                  Active Jobs ({stats.active})
                </TabsTrigger>
                <TabsTrigger value="completed" data-testid="tab-completed-jobs">
                  Completed ({stats.completed})
                </TabsTrigger>
                <TabsTrigger value="stores" data-testid="tab-my-stores">
                  <Store className="w-4 h-4 mr-1" />
                  My Stores ({myStores.length})
                </TabsTrigger>
              </TabsList>
            </CardHeader>

            <TabsContent value="available">
              <CardContent>
                <div className="space-y-4">
                  {availableRequests.length > 0 ? (
                    availableRequests.map((request: any) => (
                      <div 
                        key={request.id} 
                        className="border border-border rounded-lg p-6 hover:shadow-md transition-shadow"
                        data-testid={`job-${request.id}`}
                      >
                        <div className="flex justify-between items-start mb-4">
                          <div>
                            <h3 className="font-semibold text-foreground text-lg">{request.description}</h3>
                            <p className="text-sm text-muted-foreground">
                              Posted {new Date(request.createdAt).toLocaleDateString()}
                            </p>
                          </div>
                          <div className="flex items-center space-x-2">
                            <Badge className={getUrgencyColor(request.urgency)}>
                              {request.urgency} Priority
                            </Badge>
                            <Badge variant="outline">{request.budget}</Badge>
                          </div>
                        </div>

                        <div className="flex items-center space-x-4 text-sm text-muted-foreground mb-4">
                          <div className="flex items-center">
                            <MapPin className="w-4 h-4 mr-1" />
                            <span>{request.location}</span>
                          </div>
                          <div className="flex items-center">
                            <User className="w-4 h-4 mr-1" />
                            <span>Resident Request</span>
                          </div>
                        </div>

                        {request.specialInstructions && (
                          <p className="text-sm text-foreground mb-4 italic">
                            "{request.specialInstructions}"
                          </p>
                        )}

                        <div className="flex justify-between items-center">
                          <div className="text-sm">
                            <span className="text-muted-foreground">Category:</span>
                            <span className="font-medium text-foreground ml-1">
                              {request.category.replace('_', ' ').replace(/\b\w/g, (l: string) => l.toUpperCase())}
                            </span>
                          </div>
                          <Button 
                            onClick={() => acceptJobMutation.mutate(request.id)}
                            disabled={acceptJobMutation.isPending}
                            data-testid={`button-accept-${request.id}`}
                          >
                            {acceptJobMutation.isPending ? "Accepting..." : "Accept Job"}
                          </Button>
                        </div>
                      </div>
                    ))
                  ) : (
                    <div className="text-center py-8 text-muted-foreground">
                      <Briefcase className="w-12 h-12 mx-auto mb-4 opacity-50" />
                      <p>No available jobs at the moment</p>
                      <p className="text-sm">New requests will appear here automatically</p>
                    </div>
                  )}
                </div>
              </CardContent>
            </TabsContent>

            <TabsContent value="active">
              <CardContent>
                <div className="space-y-4">
                  {activeJobs.length > 0 ? (
                    activeJobs.map((job: any) => (
                      <div 
                        key={job.id} 
                        className="border border-border rounded-lg p-6 bg-blue-50/50"
                        data-testid={`active-job-${job.id}`}
                      >
                        <div className="flex justify-between items-start mb-4">
                          <div>
                            <h3 className="font-semibold text-foreground text-lg">{job.description}</h3>
                            <p className="text-sm text-muted-foreground">
                              Accepted {new Date(job.updatedAt).toLocaleDateString()}
                            </p>
                          </div>
                          <Badge className={getStatusColor(job.status)}>
                            {job.status.replace('_', ' ').replace(/\b\w/g, (l: string) => l.toUpperCase())}
                          </Badge>
                        </div>

                        <div className="grid grid-cols-1 md:grid-cols-3 gap-4 mb-4">
                          <div className="text-sm">
                            <span className="text-muted-foreground">Budget:</span>
                            <span className="font-medium text-foreground ml-1">{job.budget}</span>
                          </div>
                          <div className="text-sm">
                            <span className="text-muted-foreground">Location:</span>
                            <span className="font-medium text-foreground ml-1">{job.location}</span>
                          </div>
                          <div className="text-sm">
                            <span className="text-muted-foreground">Urgency:</span>
                            <span className="font-medium text-foreground ml-1">
                              {job.urgency} priority
                            </span>
                          </div>
                        </div>

                        <div className="flex justify-between items-center">
                          <div className="flex space-x-2">
                            <Button size="sm" variant="outline">
                              <Phone className="w-4 h-4 mr-2" />
                              Contact Customer
                            </Button>
                          </div>
                          <div className="flex space-x-2">
                            {job.status === 'assigned' && (
                              <Button 
                                size="sm"
                                onClick={() => updateJobStatusMutation.mutate({ 
                                  requestId: job.id, 
                                  status: 'in_progress' 
                                })}
                                disabled={updateJobStatusMutation.isPending}
                                data-testid={`button-start-${job.id}`}
                              >
                                Start Job
                              </Button>
                            )}
                            {job.status === 'in_progress' && (
                              <Button 
                                size="sm"
                                onClick={() => updateJobStatusMutation.mutate({ 
                                  requestId: job.id, 
                                  status: 'completed' 
                                })}
                                disabled={updateJobStatusMutation.isPending}
                                data-testid={`button-complete-${job.id}`}
                              >
                                Mark Complete
                              </Button>
                            )}
                          </div>
                        </div>
                      </div>
                    ))
                  ) : (
                    <div className="text-center py-8 text-muted-foreground">
                      <Clock className="w-12 h-12 mx-auto mb-4 opacity-50" />
                      <p>No active jobs</p>
                      <p className="text-sm">Accepted jobs will appear here</p>
                    </div>
                  )}
                </div>
              </CardContent>
            </TabsContent>

            <TabsContent value="completed">
              <CardContent>
                <div className="space-y-4">
                  {completedJobs.length > 0 ? (
                    completedJobs.map((job: any) => (
                      <div 
                        key={job.id} 
                        className="border border-border rounded-lg p-6"
                        data-testid={`completed-job-${job.id}`}
                      >
                        <div className="flex justify-between items-start mb-4">
                          <div>
                            <h3 className="font-semibold text-foreground text-lg">{job.description}</h3>
                            <p className="text-sm text-muted-foreground">
                              Completed {new Date(job.updatedAt).toLocaleDateString()}
                            </p>
                          </div>
                          <div className="flex items-center space-x-2">
                            <div className="flex items-center">
                              <Star className="w-4 h-4 text-yellow-400 fill-current" />
                              <span className="ml-1 text-sm font-medium">5.0</span>
                            </div>
                            <Badge className="bg-green-100 text-green-800">Completed</Badge>
                          </div>
                        </div>

                        <div className="flex justify-between items-center">
                          <div className="flex items-center space-x-4">
                            <div className="text-sm">
                              <span className="text-muted-foreground">Earned:</span>
                              <span className="font-medium text-foreground ml-1">{job.budget}</span>
                            </div>
                            <div className="text-sm">
                              <span className="text-muted-foreground">Location:</span>
                              <span className="font-medium text-foreground ml-1">{job.location}</span>
                            </div>
                          </div>
                          <Button variant="outline" size="sm">
                            View Details
                          </Button>
                        </div>
                      </div>
                    ))
                  ) : (
                    <div className="text-center py-8 text-muted-foreground">
                      <CheckCircle className="w-12 h-12 mx-auto mb-4 opacity-50" />
                      <p>No completed jobs yet</p>
                      <p className="text-sm">Completed jobs will appear here</p>
                    </div>
                  )}
                </div>
              </CardContent>
            </TabsContent>

            <TabsContent value="stores">
              <CardContent>
                <div className="mb-4 flex justify-between items-center">
                  <div>
                    <h3 className="text-lg font-semibold">My Stores</h3>
                    <p className="text-sm text-muted-foreground">Manage your marketplace stores and items</p>
                  </div>
                  <Dialog open={isCreateStoreDialogOpen} onOpenChange={setIsCreateStoreDialogOpen}>
                    <DialogTrigger asChild>
                      <Button data-testid="button-create-store">
                        <Plus className="w-4 h-4 mr-2" />
                        Create Store
                      </Button>
                    </DialogTrigger>
                    <DialogContent className="sm:max-w-md">
                      <DialogHeader>
                        <DialogTitle>Create New Store</DialogTitle>
                      </DialogHeader>
                      <div className="space-y-4 py-4">
                        <div className="space-y-2">
                          <Label htmlFor="name">Store Name *</Label>
                          <Input
                            id="name"
                            value={storeFormData.name}
                            onChange={(e) => setStoreFormData({ ...storeFormData, name: e.target.value })}
                            placeholder="e.g., Fresh Groceries Store"
                            data-testid="input-store-name"
                          />
                        </div>
                        <div className="space-y-2">
                          <Label htmlFor="description">Description</Label>
                          <Textarea
                            id="description"
                            value={storeFormData.description}
                            onChange={(e) => setStoreFormData({ ...storeFormData, description: e.target.value })}
                            placeholder="Describe your store"
                            data-testid="input-store-description"
                          />
                        </div>
                        <div className="space-y-2">
                          <Label htmlFor="location">Location *</Label>
                          <Input
                            id="location"
                            value={storeFormData.location}
                            onChange={(e) => setStoreFormData({ ...storeFormData, location: e.target.value })}
                            placeholder="e.g., Block A, Ground Floor"
                            data-testid="input-store-location"
                          />
                        </div>
                        <div className="space-y-2">
                          <Label htmlFor="phone">Phone</Label>
                          <Input
                            id="phone"
                            value={storeFormData.phone}
                            onChange={(e) => setStoreFormData({ ...storeFormData, phone: e.target.value })}
                            placeholder="+234..."
                            data-testid="input-store-phone"
                          />
                        </div>
                        <div className="space-y-2">
                          <Label htmlFor="email">Email</Label>
                          <Input
                            id="email"
                            type="email"
                            value={storeFormData.email}
                            onChange={(e) => setStoreFormData({ ...storeFormData, email: e.target.value })}
                            placeholder="store@example.com"
                            data-testid="input-store-email"
                          />
                        </div>
                        <div className="p-3 bg-blue-50 dark:bg-blue-900/20 border border-blue-200 dark:border-blue-800 rounded-md">
                          <p className="text-sm text-blue-800 dark:text-blue-200">
                            <strong>Note:</strong> Your store will be submitted for admin review. Once approved, admins will allocate estates based on proximity to your location.
                          </p>
                        </div>
                      </div>
                      <div className="flex justify-end space-x-2">
                        <Button 
                          variant="outline" 
                          onClick={() => setIsCreateStoreDialogOpen(false)}
                          data-testid="button-cancel-store"
                        >
                          Cancel
                        </Button>
                        <Button 
                          onClick={() => createStoreMutation.mutate(storeFormData)}
                          disabled={!storeFormData.name || !storeFormData.location || createStoreMutation.isPending}
                          data-testid="button-submit-store"
                        >
                          {createStoreMutation.isPending ? "Submitting..." : "Submit for Approval"}
                        </Button>
                      </div>
                    </DialogContent>
                  </Dialog>
                </div>

                <div className="space-y-4">
                  {isLoadingStores ? (
                    <div className="text-center py-8 text-muted-foreground">
                      <p>Loading your stores...</p>
                    </div>
                  ) : myStores.length > 0 ? (
                    myStores.map((store: any) => (
                      <div
                        key={store.id}
                        className="border border-border rounded-lg p-6 hover:shadow-md transition-shadow"
                        data-testid={`store-${store.id}`}
                      >
                        <div className="flex justify-between items-start mb-4">
                          <div className="flex-1">
                            <div className="flex items-center gap-2 mb-2">
                              <Store className="w-5 h-5 text-primary" />
                              <h3 className="font-semibold text-foreground text-lg">{store.name}</h3>
                              {store.isActive ? (
                                <Badge className="bg-green-100 text-green-800">Active</Badge>
                              ) : (
                                <Badge variant="outline">Inactive</Badge>
                              )}
                            </div>
                            {store.description && (
                              <p className="text-sm text-muted-foreground mb-3">{store.description}</p>
                            )}
                            <div className="grid grid-cols-1 md:grid-cols-3 gap-3 text-sm">
                              <div className="flex items-center text-muted-foreground">
                                <MapPin className="w-4 h-4 mr-1" />
                                <span>{store.location}</span>
                              </div>
                              {store.phone && (
                                <div className="flex items-center text-muted-foreground">
                                  <Phone className="w-4 h-4 mr-1" />
                                  <span>{store.phone}</span>
                                </div>
                              )}
                              {store.membership && (
                                <div className="flex items-center text-muted-foreground">
                                  <Badge variant="outline" className="text-xs">
                                    {store.membership.role}
                                  </Badge>
                                  {store.membership.canManageItems && (
                                    <span className="text-xs ml-2">• Can manage items</span>
                                  )}
                                </div>
                              )}
                            </div>
                          </div>
                        </div>
                        <div className="flex justify-between items-center pt-4 border-t">
                          <div className="flex space-x-4 text-sm text-muted-foreground">
                            <div className="flex items-center">
                              <Package className="w-4 h-4 mr-1" />
                              <span>0 items</span>
                            </div>
                            <div className="flex items-center">
                              <User className="w-4 h-4 mr-1" />
                              <span>0 orders</span>
                            </div>
                          </div>
                          <div className="flex space-x-2">
                            <Link href={`/provider/stores/${store.id}/items`}>
                              <Button 
                                variant="outline" 
                                size="sm"
                                data-testid={`button-manage-items-${store.id}`}
                              >
                                <Package className="w-4 h-4 mr-1" />
                                Manage Items
                              </Button>
                            </Link>
                            <Button 
                              variant="outline" 
                              size="sm"
                              data-testid={`button-view-orders-${store.id}`}
                            >
                              View Orders
                            </Button>
                          </div>
                        </div>
                      </div>
                    ))
                  ) : (
                    <div className="text-center py-12 text-muted-foreground">
                      <Store className="w-16 h-16 mx-auto mb-4 opacity-50" />
                      <h3 className="font-medium text-lg mb-2">No stores yet</h3>
                      <p className="text-sm mb-4">Create your first store to start selling items in the marketplace</p>
                      <Button
                        onClick={() => setIsCreateStoreDialogOpen(true)}
                        data-testid="button-create-first-store"
                      >
                        <Plus className="w-4 h-4 mr-2" />
                        Create Your First Store
                      </Button>
                    </div>
                  )}
                </div>
              </CardContent>
            </TabsContent>
          </Tabs>
        </Card>
      </div>
    </div>
  );
}

