// Recent Activity Component
const RecentActivity = () => {
  const [dateFrom, setDateFrom] = useState("");
  const [dateTo, setDateTo] = useState("");
  const [search, setSearch] = useState("");
  const [limit, setLimit] = useState(10);

  const { data: activities, isLoading } = useQuery({
    queryKey: ["/api/admin/audit-logs", { limit, search, dateFrom, dateTo }],
    queryFn: () => {
      const params = new URLSearchParams();
      if (search) params.append("search", search);
      if (dateFrom) params.append("dateFrom", dateFrom);
      if (dateTo) params.append("dateTo", dateTo);
      params.append("limit", limit.toString());

      const queryString = params.toString();
      return adminApiRequest(
        "GET",
        `/api/admin/audit-logs${queryString ? "?" + queryString : ""}`,
      );
    },
  });

  const exportToCsv = () => {
    if (!activities || activities.length === 0) return;

    const headers = ["Date", "User", "Action", "Target", "Details"];
    const csvContent = [
      headers.join(","),
      ...activities.map((activity: any) =>
        [
          new Date(activity.createdAt).toLocaleString(),
          activity.user?.name || "System",
          activity.action || "",
          activity.target || "",
          activity.details?.replace(/,/g, ";") || "",
        ]
          .map((field) => `"${field}"`)
          .join(","),
      ),
    ].join("\n");

    const blob = new Blob([csvContent], { type: "text/csv;charset=utf-8;" });
    const link = document.createElement("a");
    const url = URL.createObjectURL(blob);
    link.setAttribute("href", url);
    link.setAttribute(
      "download",
      `activity-logs-${new Date().toISOString().split("T")[0]}.csv`,
    );
    link.style.visibility = "hidden";
    document.body.appendChild(link);
    link.click();
    document.body.removeChild(link);
  };

  const getActivityIcon = (action: string) => {
    switch (action?.toLowerCase()) {
      case "create":
      case "register":
        return <Plus className="w-4 h-4 text-green-600" />;
      case "update":
      case "edit":
        return <Edit className="w-4 h-4 text-blue-600" />;
      case "delete":
      case "remove":
        return <XCircle className="w-4 h-4 text-red-600" />;
      case "approve":
        return <CheckCircle className="w-4 h-4 text-green-600" />;
      case "reject":
        return <XCircle className="w-4 h-4 text-orange-600" />;
      case "login":
        return <LogOut className="w-4 h-4 text-purple-600" />;
      default:
        return <ClipboardList className="w-4 h-4 text-gray-600" />;
    }
  };

  const getActivityBgColor = (action: string) => {
    switch (action?.toLowerCase()) {
      case "create":
      case "register":
      case "approve":
        return "bg-green-100";
      case "update":
      case "edit":
        return "bg-blue-100";
      case "delete":
      case "remove":
        return "bg-red-100";
      case "reject":
        return "bg-orange-100";
      case "login":
        return "bg-purple-100";
      default:
        return "bg-gray-100";
    }
  };

  return (
    <Card>
      <CardHeader>
        <div className="flex items-center justify-between">
          <CardTitle className="flex items-center gap-2">
            <Clock className="w-5 h-5" />
            Recent Activity
          </CardTitle>
          <div className="flex items-center gap-2">
            <Button
              variant="outline"
              size="sm"
              onClick={exportToCsv}
              disabled={!activities || activities.length === 0}
              data-testid="button-export-activity"
            >
              <Download className="w-4 h-4 mr-2" />
              Export CSV
            </Button>
          </div>
        </div>
      </CardHeader>
      <CardContent>
        {/* Filters */}
        <div className="grid grid-cols-1 md:grid-cols-4 gap-4 mb-4">
          <div>
            <Label htmlFor="dateFrom" className="text-sm">
              From Date
            </Label>
            <Input
              id="dateFrom"
              type="date"
              value={dateFrom}
              onChange={(e) => setDateFrom(e.target.value)}
              className="mt-1"
              data-testid="input-date-from"
            />
          </div>
          <div>
            <Label htmlFor="dateTo" className="text-sm">
              To Date
            </Label>
            <Input
              id="dateTo"
              type="date"
              value={dateTo}
              onChange={(e) => setDateTo(e.target.value)}
              className="mt-1"
              data-testid="input-date-to"
            />
          </div>
          <div>
            <Label htmlFor="activitySearch" className="text-sm">
              Search
            </Label>
            <Input
              id="activitySearch"
              placeholder="Search activities..."
              value={search}
              onChange={(e) => setSearch(e.target.value)}
              className="mt-1"
              data-testid="input-search-activity"
            />
          </div>
          <div>
            <Label htmlFor="limit" className="text-sm">
              Show Records
            </Label>
            <Select
              value={limit.toString()}
              onValueChange={(value) => setLimit(Number(value))}
            >
              <SelectTrigger
                className="mt-1"
                data-testid="select-activity-limit"
              >
                <SelectValue />
              </SelectTrigger>
              <SelectContent>
                <SelectItem value="10">10</SelectItem>
                <SelectItem value="25">25</SelectItem>
                <SelectItem value="50">50</SelectItem>
                <SelectItem value="100">100</SelectItem>
              </SelectContent>
            </Select>
          </div>
        </div>

        {/* Activity List */}
        <div className="space-y-3">
          {isLoading ? (
            <div className="space-y-3">
              {Array.from({ length: 5 }).map((_, i) => (
                <div
                  key={i}
                  className="flex items-center space-x-4 animate-pulse"
                >
                  <div className="w-8 h-8 bg-gray-200 rounded-full"></div>
                  <div className="flex-1 space-y-1">
                    <div className="h-4 bg-gray-200 rounded w-3/4"></div>
                    <div className="h-3 bg-gray-200 rounded w-1/2"></div>
                  </div>
                </div>
              ))}
            </div>
          ) : activities && activities.length > 0 ? (
            activities.map((activity: any, index: number) => (
              <div
                key={activity._id || index}
                className="flex items-center space-x-4 p-3 hover:bg-gray-50 rounded-lg"
              >
                <div
                  className={`w-8 h-8 ${getActivityBgColor(activity.action)} rounded-full flex items-center justify-center`}
                >
                  {getActivityIcon(activity.action)}
                </div>
                <div className="flex-1">
                  <p
                    className="text-sm font-medium"
                    data-testid={`activity-action-${index}`}
                  >
                    {activity.action || "Unknown action"}{" "}
                    {activity.target && `- ${activity.target}`}
                  </p>
                  <p
                    className="text-xs text-muted-foreground"
                    data-testid={`activity-details-${index}`}
                  >
                    {activity.user?.name || "System"} •{" "}
                    {activity.details || "No details"} •{" "}
                    {activity.createdAt
                      ? new Date(activity.createdAt).toLocaleString()
                      : "Unknown time"}
                  </p>
                </div>
              </div>
            ))
          ) : (
            <div className="text-center py-8 text-gray-500">
              <ClipboardList className="w-8 h-8 mx-auto mb-2 text-gray-400" />
              <p>No recent activity found</p>
              {(dateFrom || dateTo || search) && (
                <Button
                  variant="link"
                  size="sm"
                  onClick={() => {
                    setDateFrom("");
                    setDateTo("");
                    setSearch("");
                  }}
                  className="mt-2"
                >
                  Clear filters
                </Button>
              )}
            </div>
          )}
        </div>
      </CardContent>
    </Card>
  );
};

